import { AbsoluteFill, continueRender, delayRender } from "@vendor/remotion";
import type React from "react";
import { useEffect, useState } from "react";
import { ensureFontsLoaded } from "../landing-hero/shared/fonts";

interface PackageCard {
  description: string;
  install: string;
  label: string;
  name: string;
}

const PACKAGES: PackageCard[] = [
  {
    label: "SDK",
    name: "lightfast",
    description: "Typed access to the Lightfast API from any Node.js runtime.",
    install: "npm install lightfast",
  },
  {
    label: "MCP SERVER",
    name: "@lightfastai/mcp",
    description: "Expose Lightfast to AI agents over Model Context Protocol.",
    install: "npm install @lightfastai/mcp",
  },
];

const CARD_WIDTH = 440;
const CARD_HEIGHT = 320;
const CARD_GAP = 24;

export const ChangelogV010SdkMcp: React.FC = () => {
  const [handle] = useState(() => delayRender("Loading fonts"));

  useEffect(() => {
    void ensureFontsLoaded()
      .then(() => continueRender(handle))
      .catch((err: unknown) => {
        console.error("Font loading failed:", err);
        continueRender(handle);
      });
  }, [handle]);

  return (
    <AbsoluteFill className="bg-card">
      <div
        className="absolute top-1/2 left-1/2 flex -translate-x-1/2 -translate-y-1/2 flex-row"
        style={{ gap: CARD_GAP }}
      >
        {PACKAGES.map((pkg) => (
          <div
            className="flex flex-col justify-between rounded-md border border-border/50 p-6 font-sans"
            key={pkg.name}
            style={{ width: CARD_WIDTH, height: CARD_HEIGHT }}
          >
            <div className="flex flex-col gap-4">
              <span className="font-medium font-mono text-muted-foreground text-xs uppercase tracking-wide">
                {pkg.label}
              </span>
              <span className="font-medium font-mono text-foreground text-xl">
                {pkg.name}
              </span>
              <span className="text-muted-foreground text-sm leading-relaxed">
                {pkg.description}
              </span>
            </div>
            <div className="flex items-center gap-2 rounded-md border border-border/50 bg-background px-3 py-2">
              <span className="font-mono text-muted-foreground/60 text-xs">
                $
              </span>
              <span className="truncate font-mono text-foreground text-xs">
                {pkg.install}
              </span>
            </div>
          </div>
        ))}
      </div>
    </AbsoluteFill>
  );
};

